def learn(self, X, y):
    self.class_prob = numpy.zeros(self.K)
    for k in range(self.K):
        self.class_prob[k] = numpy.sum(y == k) / y.shape[0]
        X_k = X[y == k]
        self.mu[k] = numpy.mean(X_k, axis=0)
        self.Sigma[k] = numpy.cov(X_k.T)

def log_gaussian(self, X, mu, Sigma):
    N, D = X.shape
    log_prob = numpy.zeros(N)
    for i in range(N):
        diff = X[i] - mu
        log_prob[i] = -0.5 * numpy.log(numpy.linalg.det(Sigma)) - 0.5 * diff.T @ numpy.linalg.inv(Sigma) @ diff
    return log_prob

def predict(self, X):
    N = X.shape[0]
    log_posterior = numpy.zeros((N, self.K))
    for k in range(self.K):
        log_posterior[:, k] = self.log_gaussian(X, self.mu[k], self.Sigma[k])
    log_posterior += numpy.log(self.class_prob)
    return numpy.argmax(log_posterior, axis=1)
